select count(*) from orders


        and order_time > #{beginTime}


        and order_time < #{endTime}

select  count(*) from orders


        and order_time > #{beginTime}


        and order_time < #{endTime}

    and status = #{status}

select od.name as nameList,sum(od.number) as numberList from order_detail od inner join orders o on od.order_id = o.id


            and o.order_time > #{beginTime}


            and o.order_time < #{endTime}


            and o.status = #{status}


    group by od.name order by numberList desc limit 10;
